<span class="line">        <span class="token class-name">System</span><span class="token punctuation">.</span>out<span class="token punctuation">.</span><span class="token function">println</span><span class="token punctuation">(</span><span class="token string">&quot;订单 &quot;</span> <span class="token operator">+</span> orderId <span class="token operator">+</span> <span class="token string">&quot; 当前状态: &quot;</span> <span class="token operator">+</span> state<span class="token punctuation">.</span><span class="token function">getStateName</span><span class="token punctuation">(</span><span class="token punctuation">)</span><span class="token punctuation">)</span><span class="token punctuation">;</span></span>
